diff --git a/retrofit/src/main/java/retrofit2/CompletableFutureCallAdapterFactory.java b/retrofit/src/main/java/retrofit2/CompletableFutureCallAdapterFactory.java
index 305eae3..aba0299 100644
--- a/retrofit/src/main/java/retrofit2/CompletableFutureCallAdapterFactory.java
+++ b/retrofit/src/main/java/retrofit2/CompletableFutureCallAdapterFactory.java
@@ -69,6 +69,13 @@ final class CompletableFutureCallAdapterFactory extends CallAdapter.Factory {
     @Override
     public CompletableFuture<R> adapt(final Call<R> call) {
       CompletableFuture<R> future = new CallCancelCompletableFuture<>(call);
+      // Propagate future cancellation to the underlying OkHttp call to prevent leaked connections.
+      future.whenComplete(
+          (body, t) -> {
+            if (future.isCancelled()) {
+              call.cancel();
+            }
+          });
       call.enqueue(new BodyCallback(future));
       return future;
     }
@@ -114,6 +121,13 @@ final class CompletableFutureCallAdapterFactory extends CallAdapter.Factory {
     @Override
     public CompletableFuture<Response<R>> adapt(final Call<R> call) {
       CompletableFuture<Response<R>> future = new CallCancelCompletableFuture<>(call);
+      // Propagate future cancellation to the underlying OkHttp call to prevent leaked connections.
+      future.whenComplete(
+          (response, t) -> {
+            if (future.isCancelled()) {
+              call.cancel();
+            }
+          });
       call.enqueue(new ResponseCallback(future));
       return future;
     }
